def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    import pymoo
    from pymoo.indicators.hv import HV

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, m = points.shape

    def compute_hv(subset_indices):
        if len(subset_indices) == 0:
            return 0.0
        selected = points[list(subset_indices)]
        ind = HV(ref_point=reference_point)
        return ind(selected)

    def restricted_candidate_list(current_set, alpha=0.3):
        candidates = list(set(range(n)) - current_set)
        if not candidates:
            return []

        contributions = []
        for cand in candidates:
            temp_set = current_set | {cand}
            hv_with = compute_hv(temp_set)
            hv_without = compute_hv(current_set)
            contributions.append(hv_with - hv_without)

        contributions = np.array(contributions)
        max_contrib = np.max(contributions)
        min_contrib = np.min(contributions)

        threshold = min_contrib + alpha * (max_contrib - min_contrib)
        rcl = [candidates[i] for i in range(len(candidates)) if contributions[i] >= threshold]

        return rcl if rcl else candidates

    def grasp_construction(alpha=0.3):
        current_set = set()
        while len(current_set) < k:
            rcl = restricted_candidate_list(current_set, alpha)
            if not rcl:
                break
            chosen = random.choice(rcl)
            current_set.add(chosen)
        return current_set

    def local_search(solution_set):
        current_set = set(solution_set)
        improved = True

        while improved:
            improved = False
            current_hv = compute_hv(current_set)

            for s in list(current_set):
                for r in set(range(n)) - current_set:
                    new_set = (current_set - {s}) | {r}
                    new_hv = compute_hv(new_set)

                    if new_hv > current_hv:
                        current_set = new_set
                        current_hv = new_hv
                        improved = True
                        break
                if improved:
                    break

        return current_set

    def path_relinking(set1, set2):
        symmetric_diff = list(set1 ^ set2)
        random.shuffle(symmetric_diff)

        current_set = set(set1)
        best_set = set(set1)
        best_hv = compute_hv(set1)

        for elem in symmetric_diff:
            if elem in current_set:
                current_set.remove(elem)
            else:
                current_set.add(elem)

            if len(current_set) == k:
                current_hv = compute_hv(current_set)
                if current_hv > best_hv:
                    best_set = set(current_set)
                    best_hv = current_hv

        return best_set

    best_solution = None
    best_hv = -np.inf

    for iteration in range(10):
        alpha = random.uniform(0.1, 0.5)
        constructed = grasp_construction(alpha)

        if len(constructed) < k:
            remaining = list(set(range(n)) - constructed)
            needed = k - len(constructed)
            constructed.update(random.sample(remaining, min(needed, len(remaining))))

        improved = local_search(constructed)

        if best_solution is None:
            best_solution = improved
            best_hv = compute_hv(improved)
        else:
            relinked = path_relinking(best_solution, improved)
            relinked_hv = compute_hv(relinked)

            if relinked_hv > best_hv:
                best_solution = relinked
                best_hv = relinked_hv

    return points[list(best_solution)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import random
    from pymoo.indicators.hv import HV

    n, m = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    ind = HV(ref_point=reference_point)

    def compute_hv(indices):
        if len(indices) == 0:
            return 0.0
        return ind(points[list(indices)])

    # Initialize with random subset
    current_set = set(random.sample(range(n), k))
    current_hv = compute_hv(current_set)
    best_set = set(current_set)
    best_hv = current_hv

    # Adaptive cooling parameters
    T_initial = current_hv * 0.1
    T = T_initial
    cooling_rate = 0.95
    min_T = 1e-6
    max_iter = 1000
    iter_per_temp = 50

    iteration = 0
    while T > min_T and iteration < max_iter:
        for _ in range(iter_per_temp):
            # Generate neighbor by swapping one point
            if len(current_set) < k:
                # Add a random point if set is too small
                candidates = list(set(range(n)) - current_set)
                if candidates:
                    new_point = random.choice(candidates)
                    new_set = current_set | {new_point}
                else:
                    continue
            else:
                # Swap one selected point with one unselected point
                remove_cand = random.choice(list(current_set))
                add_candidates = list(set(range(n)) - current_set)
                if not add_candidates:
                    continue
                add_cand = random.choice(add_candidates)
                new_set = (current_set - {remove_cand}) | {add_cand}

            new_hv = compute_hv(new_set)
            delta = new_hv - current_hv

            # Acceptance criterion
            if delta > 0 or random.random() < np.exp(delta / T):
                current_set = new_set
                current_hv = new_hv

                if current_hv > best_hv:
                    best_set = set(current_set)
                    best_hv = current_hv

        # Adaptive cooling
        T *= cooling_rate
        iteration += 1

        # Occasionally reheat to escape local optima
        if iteration % 20 == 0 and current_hv < best_hv * 0.95:
            T = min(T_initial * 0.5, T * 2.0)

    # Final local improvement phase
    improved = True
    while improved:
        improved = False
        for s in list(best_set):
            for r in set(range(n)) - best_set:
                trial_set = (best_set - {s}) | {r}
                trial_hv = compute_hv(trial_set)
                if trial_hv > best_hv:
                    best_set = trial_set
                    best_hv = trial_hv
                    improved = True
                    break
            if improved:
                break

    return points[list(best_set)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random

    n, d = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Fast hypervolume calculation
    def compute_hv(indices):
        if len(indices) == 0:
            return 0.0
        hv = pg.hypervolume(points[indices])
        return hv.compute(reference_point)

    # Fast contribution calculation
    def compute_contrib(idx, current_set):
        if len(current_set) == 0:
            return compute_hv([idx])
        combined = list(current_set) + [idx]
        return compute_hv(combined) - compute_hv(list(current_set))

    # Phase 1: Adaptive greedy with lookahead
    selected = set()
    remaining = set(range(n))

    # Initial selection: pick extreme points first
    for dim in range(d):
        if len(selected) >= k:
            break
        best_idx = max(remaining, key=lambda i: points[i, dim])
        if best_idx not in selected:
            selected.add(best_idx)
            remaining.remove(best_idx)

    # Greedy selection with adaptive lookahead
    while len(selected) < k:
        candidates = list(remaining)

        if len(selected) < k // 2:
            # Early stage: use 2-step lookahead
            best_score = -np.inf
            best_idx = None

            for idx in candidates:
                # Base contribution
                base_contrib = compute_contrib(idx, selected)

                # Lookahead: try adding this point, then find best companion
                temp_set = selected | {idx}
                remaining_after = remaining - {idx}

                if remaining_after:
                    # Sample for efficiency
                    sample_size = min(8, len(remaining_after))
                    sampled = random.sample(list(remaining_after), sample_size)

                    best_companion = max(sampled, 
                                       key=lambda i: compute_contrib(i, temp_set))
                    lookahead_gain = compute_contrib(best_companion, temp_set)

                    # Combined score
                    score = base_contrib + 0.4 * lookahead_gain
                else:
                    score = base_contrib

                # Diversity adjustment
                if selected:
                    min_dist = min(np.linalg.norm(points[idx] - points[s]) 
                                 for s in selected)
                    diversity_bonus = min_dist / np.max(points) * 0.2
                    score *= (1.0 + diversity_bonus)

                if score > best_score:
                    best_score = score
                    best_idx = idx

            if best_idx is not None:
                selected.add(best_idx)
                remaining.remove(best_idx)
        else:
            # Late stage: pure greedy with diversity
            best_idx = max(candidates, 
                          key=lambda i: compute_contrib(i, selected))
            selected.add(best_idx)
            remaining.remove(best_idx)

    # Phase 2: Enhanced local search with adaptive neighborhood
    current_hv = compute_hv(list(selected))
    improved = True
    iteration = 0

    while improved and iteration < 20:
        improved = False
        iteration += 1

        # Adaptive neighborhood size
        neighborhood_size = min(15, n - k)

        # Try improving swaps
        selected_list = list(selected)
        remaining_list = list(remaining)

        # Sort by potential: for selected points, sort by lowest contribution
        selected_sorted = sorted(selected_list,
                               key=lambda i: compute_contrib(i, selected - {i}))

        # For remaining points, sort by highest potential contribution
        remaining_sorted = sorted(remaining_list,
                                key=lambda i: compute_contrib(i, selected),
                                reverse=True)

        # Try swaps starting with worst selected and best remaining
        for s_idx in selected_sorted[:min(5, k)]:
            for r_idx in remaining_sorted[:neighborhood_size]:
                # Try swap
                new_set = (selected - {s_idx}) | {r_idx}
                new_hv = compute_hv(list(new_set))

                if new_hv > current_hv + 1e-10:
                    selected = new_set
                    remaining = (remaining - {r_idx}) | {s_idx}
                    current_hv = new_hv
                    improved = True
                    break

            if improved:
                break

        # If no swap improved, try 2-point exchange
        if not improved and k >= 2:
            for i in range(min(3, k)):
                for j in range(i+1, min(5, k)):
                    s1, s2 = selected_sorted[i], selected_sorted[j]

                    for r1 in remaining_sorted[:min(5, len(remaining_sorted))]:
                        for r2 in remaining_sorted[:min(5, len(remaining_sorted))]:
                            if r1 == r2:
                                continue

                            new_set = (selected - {s1, s2}) | {r1, r2}
                            new_hv = compute_hv(list(new_set))

                            if new_hv > current_hv + 1e-10:
                                selected = new_set
                                remaining = (remaining - {r1, r2}) | {s1, s2}
                                current_hv = new_hv
                                improved = True
                                break
                        if improved:
                            break
                    if improved:
                        break
                if improved:
                    break

    # Phase 3: Final refinement with single-point optimization
    for _ in range(3):
        current_contribs = {i: compute_contrib(i, selected - {i}) 
                          for i in selected}

        # Try replacing each selected point
        for s_idx in list(selected):
            best_improvement = 0
            best_replace = None

            for r_idx in remaining:
                # Quick estimate: contribution of new point minus contribution of removed point
                est_improvement = compute_contrib(r_idx, selected - {s_idx}) - current_contribs[s_idx]

                if est_improvement > best_improvement:
                    # Exact calculation
                    new_set = (selected - {s_idx}) | {r_idx}
                    new_hv = compute_hv(list(new_set))

                    if new_hv > current_hv + 1e-10:
                        best_improvement = new_hv - current_hv
                        best_replace = r_idx

            if best_replace is not None:
                selected = (selected - {s_idx}) | {best_replace}
                remaining = (remaining - {best_replace}) | {s_idx}
                current_hv += best_improvement

    return points[list(selected)]
